import React, { useState } from "react";
import Card from "react-bootstrap/Card";
import Button from "react-bootstrap/Button";
import { CgWebsite } from "react-icons/cg";
import { CgDesktop } from "react-icons/cg";
import { HiOutlineOfficeBuilding } from "react-icons/hi";

function InternshipCard(props) {
  const [imgError, setImgError] = useState(false);
  const imgSrc = imgError ? null : props.imgPath;

  return (
    <Card className="internship-card-view">
      <div className="internship-card-img-wrapper">
        {imgSrc ? (
          <Card.Img
            variant="top"
            src={imgSrc}
            alt={props.title}
            onError={() => setImgError(true)}
          />
        ) : (
          <div className="internship-card-img-fallback">
            <HiOutlineOfficeBuilding size={48} />
          </div>
        )}
      </div>
      <Card.Body>
        <Card.Title>{props.title}</Card.Title>
        <Card.Text style={{ textAlign: "justify" }}>
          {props.description}
        </Card.Text>
        <Button variant="primary" href={props.ghLink} target="_blank">
          <CgDesktop /> &nbsp;
          {props.isBlog ? "Blog" : "Journey"}
        </Button>
        {"\n"}
        {"\n"}

        {/* If the component contains Demo link and if it's not a Blog then, it will render the below component  */}

        {!props.isBlog && props.demoLink && (
          <Button
            variant="primary"
            href={props.demoLink}
            target="_blank"
            style={{ marginLeft: "10px" }}
          >
            <CgWebsite /> &nbsp;
            {"Certificate"}
          </Button>
        )}
      </Card.Body>
    </Card>
  );
}
export default InternshipCard;
